{"code":"@custom-variant dark (&:is(.dark *));

:root {
  --font-size: 14px;
  --background: #f8faf9;
  --foreground: #1a1a1a;
  --card: #ffffff;
  --card-foreground: #1a1a1a;
  --popover: #ffffff;
  --popover-foreground: #1a1a1a;
  --primary: #22c55e;
  --primary-foreground: #ffffff;
  --secondary: #f1f5f4;
  --secondary-foreground: #1a1a1a;
  --muted: #f1f5f4;
  --muted-foreground: #6b7280;
  --accent: #dcfce7;
  --accent-foreground: #166534;
  --destructive: #ef4444;
  --destructive-foreground: #ffffff;
  --border: #e5e7eb;
  --input: transparent;
  --input-background: #ffffff;
  --switch-background: #e5e7eb;
  --font-weight-medium: 500;
  --font-weight-normal: 400;
  --ring: #22c55e;
  --chart-1: #22c55e;
  --chart-2: #3b82f6;
  --chart-3: #f59e0b;
  --chart-4: #ef4444;
  --chart-5: #8b5cf6;
  --radius: 0.625rem;
  --sidebar: #1e3a2e;
  --sidebar-foreground: #ffffff;
  --sidebar-primary: #22c55e;
  --sidebar-primary-foreground: #ffffff;
  --sidebar-accent: #2d5a42;
  --sidebar-accent-foreground: #ffffff;
  --sidebar-border: #2d5a42;
  --sidebar-ring: #22c55e;
}

.dark {
  --background: #0f172a;
  --foreground: #f8fafc;
  --card: #1e293b;
  --card-foreground: #f8fafc;
  --popover: #1e293b;
  --popover-foreground: #f8fafc;
  --primary: #22c55e;
  --primary-foreground: #ffffff;
  --secondary: #334155;
  --secondary-foreground: #f8fafc;
  --muted: #334155;
  --muted-foreground: #94a3b8;
  --accent: #1e3a2e;
  --accent-foreground: #22c55e;
  --destructive: #ef4444;
  --destructive-foreground: #ffffff;
  --border: #334155;
  --input: #334155;
  --ring: #22c55e;
  --font-weight-medium: 500;
  --font-weight-normal: 400;
  --chart-1: #22c55e;
  --chart-2: #3b82f6;
  --chart-3: #f59e0b;
  --chart-4: #ef4444;
  --chart-5: #8b5cf6;
  --sidebar: #1e3a2e;
  --sidebar-foreground: #ffffff;
  --sidebar-primary: #22c55e;
  --sidebar-primary-foreground: #ffffff;
  --sidebar-accent: #2d5a42;
  --sidebar-accent-foreground: #ffffff;
  --sidebar-border: #2d5a42;
  --sidebar-ring: #22c55e;
}

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-input-background: var(--input-background);
  --color-switch-background: var(--switch-background);
  --color-ring: var(--ring);
  --color-chart-1: var(--chart-1);
  --color-chart-2: var(--chart-2);
  --color-chart-3: var(--chart-3);
  --color-chart-4: var(--chart-4);
  --color-chart-5: var(--chart-5);
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);
  --color-sidebar: var(--sidebar);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-ring: var(--sidebar-ring);
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }

  body {
    @apply bg-background text-foreground;
  }
}

/**
 * Base typography. This is not applied to elements which have an ancestor with a Tailwind text class.
 */
@layer base {
  :where(:not(:has([class*=" text-"]), :not(:has([class^="text-"])))) {
    h1 {
      font-size: var(--text-2xl);
      font-weight: var(--font-weight-medium);
      line-height: 1.5;
    }

    h2 {
      font-size: var(--text-xl);
      font-weight: var(--font-weight-medium);
      line-height: 1.5;
    }

    h3 {
      font-size: var(--text-lg);
      font-weight: var(--font-weight-medium);
      line-height: 1.5;
    }

    h4 {
      font-size: var(--text-base);
      font-weight: var(--font-weight-medium);
      line-height: 1.5;
    }

    p {
      font-size: var(--text-base);
      font-weight: var(--font-weight-normal);
      line-height: 1.5;
    }

    label {
      font-size: var(--text-base);
      font-weight: var(--font-weight-medium);
      line-height: 1.5;
    }

    button {
      font-size: var(--text-base);
      font-weight: var(--font-weight-medium);
      line-height: 1.5;
    }

    input {
      font-size: var(--text-base);
      font-weight: var(--font-weight-normal);
      line-height: 1.5;
    }
  }
}

html {
  font-size: var(--font-size);
}","codeFilePath":"/styles/globals.css"}

{"code":"import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "./ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "./ui/select";
import { Badge } from "./ui/badge";
import { ConsumptionChart } from "./ConsumptionChart";
import { DemandChart } from "./DemandChart";
import { EnergyParameters } from "./EnergyParameters";
import { MultiDeviceSelector } from "./MultiDeviceSelector";

export function Dashboard() {
  const [selectedDevice, setSelectedDevice] = useState("all-devices");
  const [selectedDevices, setSelectedDevices] = useState<string[]>([]);
  const [dataMode, setDataMode] = useState("real-time");
  const [selectedDay, setSelectedDay] = useState("today");

  const devices = [
    { id: "all-devices", name: "All Devices", type: "group" },
    { id: "device-1", name: "Device 1 - Main Building", type: "device" },
    { id: "device-2", name: "Device 2 - Manufacturing Unit", type: "device" },
    { id: "device-3", name: "Device 3 - Office Block", type: "device" },
    { id: "group-1", name: "Virtual Group - Production", type: "group" },
    { id: "group-2", name: "Virtual Group - Administration", type: "group" },
  ];

  const dataModes = [
    { id: "real-time", name: "Real-Time Data" },
    { id: "historical", name: "Historical Data" },
    { id: "combined", name: "Combined View" },
  ];

  const days = [
    { id: "today", name: "Today" },
    { id: "yesterday", name: "Yesterday" },
    { id: "last-7-days", name: "Last 7 Days" },
    { id: "last-30-days", name: "Last 30 Days" },
  ];

  const isVirtualGroup = selectedDevice === "group-1" || selectedDevice === "group-2";

  return (
    <div className="min-h-screen bg-background">
      <div className="p-6 space-y-6">
        {/* Header */}
        <div className="flex flex-col space-y-2">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-3xl tracking-tight text-foreground">Hello, Liam Gallagher! 👋</h1>
              <p className="text-muted-foreground">
                What are you looking for today?
              </p>
            </div>
            <div className="flex items-center gap-2">
              <Badge className="bg-primary/10 text-primary border-primary/20 px-3 py-1">
                Real-time monitoring active
              </Badge>
            </div>
          </div>
        </div>

        {/* Filter Controls */}
        <Card className="border-border/50 shadow-sm">
          <CardHeader className="pb-4">
            <CardTitle className="text-lg text-foreground">Filters & Configuration</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              {/* Device/Group Filter */}
              <div className="space-y-2">
                <label className="text-sm text-muted-foreground font-medium">Device / Virtual Group</label>
                <Select value={selectedDevice} onValueChange={setSelectedDevice}>
                  <SelectTrigger className="border-border/50">
                    <SelectValue placeholder="Select device or group" />
                  </SelectTrigger>
                  <SelectContent>
                    {devices.map((device) => (
                      <SelectItem key={device.id} value={device.id}>
                        <div className="flex items-center gap-2">
                          {device.name}
                          <Badge variant={device.type === "group" ? "default" : "secondary"} className="text-xs">
                            {device.type}
                          </Badge>
                        </div>
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              {/* Data Mode Selection */}
              <div className="space-y-2">
                <label className="text-sm text-muted-foreground font-medium">Data Mode</label>
                <Select value={dataMode} onValueChange={setDataMode}>
                  <SelectTrigger className="border-border/50">
                    <SelectValue placeholder="Select data mode" />
                  </SelectTrigger>
                  <SelectContent>
                    {dataModes.map((mode) => (
                      <SelectItem key={mode.id} value={mode.id}>
                        {mode.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              {/* Day Filter */}
              <div className="space-y-2">
                <label className="text-sm text-muted-foreground font-medium">Time Period</label>
                <Select value={selectedDay} onValueChange={setSelectedDay}>
                  <SelectTrigger className="border-border/50">
                    <SelectValue placeholder="Select time period" />
                  </SelectTrigger>
                  <SelectContent>
                    {days.map((day) => (
                      <SelectItem key={day.id} value={day.id}>
                        {day.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Multi-Device Selection for Virtual Groups */}
        {isVirtualGroup && (
          <MultiDeviceSelector
            selectedGroup={selectedDevice}
            selectedDevices={selectedDevices}
            onDeviceSelectionChange={setSelectedDevices}
          />
        )}

        {/* Energy Parameters */}
        <EnergyParameters dataMode={dataMode} selectedDevice={selectedDevice} />

        {/* Charts Section */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Consumption Overview */}
          <ConsumptionChart selectedDay={selectedDay} selectedDevice={selectedDevice} />

          {/* Max vs Actual Demand */}
          <DemandChart dataMode={dataMode} selectedDay={selectedDay} />
        </div>
      </div>
    </div>
  );
}","codeFilePath":"/components/Dashboard.tsx"}

{"code":"import { Card, CardContent, CardHeader, CardTitle } from "./ui/card";
import { Badge } from "./ui/badge";
import { TrendingUp, TrendingDown, Minus } from "lucide-react";

interface EnergyParametersProps {
  dataMode: string;
  selectedDevice: string;
}

export function EnergyParameters({ dataMode, selectedDevice }: EnergyParametersProps) {
  // Mock data - in real app this would come from API
  const parameters = [
    {
      id: "kva",
      name: "KVA",
      fullName: "Apparent Power",
      value: "1,245.6",
      unit: "kVA",
      change: "+5.2%",
      trend: "up",
      status: "normal",
    },
    {
      id: "kwh",
      name: "KWH",
      fullName: "Energy Consumption",
      value: "8,932.4",
      unit: "kWh",
      change: "+12.8%",
      trend: "up",
      status: "high",
    },
    {
      id: "kvar",
      name: "KVAR",
      fullName: "Reactive Power",
      value: "342.1",
      unit: "kVAR",
      change: "-2.1%",
      trend: "down",
      status: "normal",
    },
    {
      id: "pf",
      name: "PF",
      fullName: "Power Factor",
      value: "0.92",
      unit: "",
      change: "0.0%",
      trend: "stable",
      status: "optimal",
    },
  ];

  const getTrendIcon = (trend: string) => {
    switch (trend) {
      case "up":
        return <TrendingUp className="size-4" />;
      case "down":
        return <TrendingDown className="size-4" />;
      default:
        return <Minus className="size-4" />;
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case "high":
        return "destructive";
      case "optimal":
        return "default";
      default:
        return "secondary";
    }
  };

  const getTrendColor = (trend: string) => {
    switch (trend) {
      case "up":
        return "text-primary";
      case "down":
        return "text-destructive";
      default:
        return "text-muted-foreground";
    }
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
      {parameters.map((param) => (
        <Card key={param.id} className="border-border/50 shadow-sm hover:shadow-md transition-shadow">
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">{param.name}</CardTitle>
            <Badge variant={getStatusColor(param.status) as any} className="text-xs">
              {param.status}
            </Badge>
          </CardHeader>
          <CardContent>
            <div className="space-y-2">
              <div className="flex items-baseline gap-1">
                <div className="text-2xl font-bold">
                  {param.value}
                </div>
                {param.unit && (
                  <div className="text-sm text-muted-foreground">
                    {param.unit}
                  </div>
                )}
              </div>

              <div className="flex items-center justify-between">
                <div className="text-xs text-muted-foreground">
                  {param.fullName}
                </div>
                <div className={`flex items-center gap-1 text-xs ${getTrendColor(param.trend)}`}>
                  {getTrendIcon(param.trend)}
                  {param.change}
                </div>
              </div>
            </div>
          </CardContent>
        </Card>
      ))}
    </div>
  );
}","codeFilePath":"/components/EnergyParameters.tsx"}

{"code":"import { Card, CardContent, CardHeader, CardTitle } from "./ui/card";
import { PieChart, Pie, Cell, ResponsiveContainer, Legend, Tooltip } from "recharts";

interface ConsumptionChartProps {
  selectedDay: string;
  selectedDevice: string;
}

export function ConsumptionChart({ selectedDay, selectedDevice }: ConsumptionChartProps) {
  // Mock data - in real app this would come from API based on filters
  const consumptionData = [
    { name: "Device 1 - Main Building", value: 2400, color: "#22c55e" },
    { name: "Device 2 - Manufacturing", value: 4567, color: "#16a34a" },
    { name: "Device 3 - Office Block", value: 1890, color: "#15803d" },
    { name: "HVAC Systems", value: 3210, color: "#166534" },
    { name: "Lighting", value: 1250, color: "#14532d" },
    { name: "Equipment", value: 2100, color: "#052e16" },
  ];

  const totalConsumption = consumptionData.reduce((sum, item) => sum + item.value, 0);

  const CustomTooltip = ({ active, payload }: any) => {
    if (active && payload && payload.length) {
      const data = payload[0];
      const percentage = ((data.value / totalConsumption) * 100).toFixed(1);
      return (
        <div className="bg-background border border-border rounded-lg p-3 shadow-lg">
          <p className="font-medium">{data.name}</p>
          <p className="text-sm text-muted-foreground">
            {data.value.toLocaleString()} kWh ({percentage}%)
          </p>
        </div>
      );
    }
    return null;
  };

  const CustomLegend = ({ payload }: any) => {
    return (
      <div className="flex flex-wrap gap-4 justify-center mt-4">
        {payload.map((entry: any, index: number) => (
          <div key={index} className="flex items-center gap-2 text-sm">
            <div 
              className="w-3 h-3 rounded-full" 
              style={{ backgroundColor: entry.color }}
            />
            <span className="text-foreground">{entry.value}</span>
          </div>
        ))}
      </div>
    );
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle>Energy Consumption Overview</CardTitle>
        <p className="text-sm text-muted-foreground">
          Distribution of energy consumption across all live devices for {selectedDay}
        </p>
      </CardHeader>
      <CardContent>
        <div className="space-y-4">
          {/* Total Consumption Summary */}
          <div className="text-center space-y-1">
            <div className="text-3xl font-bold text-foreground">
              {totalConsumption.toLocaleString()}
            </div>
            <div className="text-sm text-muted-foreground">
              Total kWh consumption
            </div>
          </div>

          {/* Pie Chart */}
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={consumptionData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={120}
                  paddingAngle={2}
                  dataKey="value"
                >
                  {consumptionData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip content={<CustomTooltip />} />
                <Legend content={<CustomLegend />} />
              </PieChart>
            </ResponsiveContainer>
          </div>

          {/* Device Status List */}
          <div className="space-y-2">
            <h4 className="text-sm font-medium">Device Status</h4>
            <div className="grid grid-cols-1 gap-2">
              {consumptionData.slice(0, 3).map((device, index) => (
                <div key={index} className="flex items-center justify-between p-2 bg-muted/50 rounded-md">
                  <div className="flex items-center gap-2">
                    <div 
                      className="w-2 h-2 rounded-full" 
                      style={{ backgroundColor: device.color }}
                    />
                    <span className="text-sm">{device.name}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="text-sm font-medium">{device.value.toLocaleString()} kWh</span>
                    <div className="w-2 h-2 bg-green-500 rounded-full" title="Active" />
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}","codeFilePath":"/components/ConsumptionChart.tsx"}

{"code":"import { Card, CardContent, CardHeader, CardTitle } from "./ui/card";
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from "recharts";

interface DemandChartProps {
  dataMode: string;
  selectedDay: string;
}

export function DemandChart({ dataMode, selectedDay }: DemandChartProps) {
  // Mock data - in real app this would come from API based on filters
  const demandData = [
    { time: "00:00", maxDemand: 1200, actualDemand: 890 },
    { time: "02:00", maxDemand: 1200, actualDemand: 750 },
    { time: "04:00", maxDemand: 1200, actualDemand: 650 },
    { time: "06:00", maxDemand: 1200, actualDemand: 980 },
    { time: "08:00", maxDemand: 1200, actualDemand: 1150 },
    { time: "10:00", maxDemand: 1200, actualDemand: 1080 },
    { time: "12:00", maxDemand: 1200, actualDemand: 1190 },
    { time: "14:00", maxDemand: 1200, actualDemand: 1240 },
    { time: "16:00", maxDemand: 1200, actualDemand: 1180 },
    { time: "18:00", maxDemand: 1200, actualDemand: 1350 },
    { time: "20:00", maxDemand: 1200, actualDemand: 1220 },
    { time: "22:00", maxDemand: 1200, actualDemand: 1010 },
  ];

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-background border border-border rounded-lg p-3 shadow-lg">
          <p className="font-medium">{`Time: ${label}`}</p>
          {payload.map((pld: any, index: number) => (
            <div key={index} className="flex items-center gap-2">
              <div 
                className="w-3 h-1 rounded" 
                style={{ backgroundColor: pld.color }}
              />
              <span className="text-sm">
                {pld.dataKey === 'maxDemand' ? 'Max Demand' : 'Actual Demand'}: {pld.value} kW
              </span>
            </div>
          ))}
        </div>
      );
    }
    return null;
  };

  // Calculate statistics
  const avgActualDemand = Math.round(demandData.reduce((sum, item) => sum + item.actualDemand, 0) / demandData.length);
  const peakDemand = Math.max(...demandData.map(item => item.actualDemand));
  const demandEfficiency = Math.round((avgActualDemand / 1200) * 100);

  return (
    <Card>
      <CardHeader>
        <CardTitle>Max vs Actual Demand</CardTitle>
        <p className="text-sm text-muted-foreground">
          Comparison of peak demand against actual usage over time ({dataMode})
        </p>
      </CardHeader>
      <CardContent>
        <div className="space-y-6">
          {/* Statistics */}
          <div className="grid grid-cols-3 gap-4">
            <div className="text-center space-y-1">
              <div className="text-xl font-bold text-foreground">{avgActualDemand} kW</div>
              <div className="text-xs text-muted-foreground">Avg Demand</div>
            </div>
            <div className="text-center space-y-1">
              <div className="text-xl font-bold text-foreground">{peakDemand} kW</div>
              <div className="text-xs text-muted-foreground">Peak Demand</div>
            </div>
            <div className="text-center space-y-1">
              <div className="text-xl font-bold text-foreground">{demandEfficiency}%</div>
              <div className="text-xs text-muted-foreground">Efficiency</div>
            </div>
          </div>

          {/* Line Chart */}
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={demandData} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" />
                <XAxis 
                  dataKey="time" 
                  stroke="hsl(var(--muted-foreground))"
                  fontSize={12}
                />
                <YAxis 
                  stroke="hsl(var(--muted-foreground))"
                  fontSize={12}
                  domain={[0, 1400]}
                />
                <Tooltip content={<CustomTooltip />} />
                <Legend />
                <Line
                  type="monotone"
                  dataKey="maxDemand"
                  stroke="#ef4444"
                  strokeWidth={2}
                  strokeDasharray="5 5"
                  name="Max Demand"
                  dot={false}
                />
                <Line
                  type="monotone"
                  dataKey="actualDemand"
                  stroke="#22c55e"
                  strokeWidth={3}
                  name="Actual Demand"
                  dot={{ fill: "#22c55e", strokeWidth: 2, r: 4 }}
                  activeDot={{ r: 6, stroke: "#22c55e", strokeWidth: 2 }}
                />
              </LineChart>
            </ResponsiveContainer>
          </div>

          {/* Demand Analysis */}
          <div className="space-y-2">
            <h4 className="text-sm font-medium">Demand Analysis</h4>
