{"code":"import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "./ui/card";
import { Badge } from "./ui/badge";
import { Leaf, TrendingDown, AlertTriangle, TreePine } from "lucide-react";

interface AnalyticsData {
  deviceId: string;
  timestamp: string;
  kvah: number;
  billing: number;
  kva: number;
  kw: number;
  kwh: number;
  pf: number;
  kvarh_lag: number;
  kvarh_lead: number;
  co2_emissions: number;
}

interface EnvironmentalImpactProps {
  data: AnalyticsData[];
}

export function EnvironmentalImpact({ data }: EnvironmentalImpactProps) {
  // Calculate environmental metrics
  const totalCO2 = data.reduce((sum, item) => sum + item.co2_emissions, 0);
  const averageCO2 = totalCO2 / data.length;
  const totalKWH = data.reduce((sum, item) => sum + item.kwh, 0);
  const emissionFactor = 0.82; // kg CO2 per kWh (India average)

  // Calculate tree equivalency (1 tree absorbs ~22 kg CO2 per year)
  const treesEquivalent = totalCO2 / 22;

  // Determine emission level
  const getEmissionLevel = (co2: number) => {
    if (co2 < 30) return { level: "Low", variant: "default" as const, color: "text-green-600" };
    if (co2 < 50) return { level: "Moderate", variant: "secondary" as const, color: "text-yellow-600" };
    return { level: "High", variant: "destructive" as const, color: "text-red-600" };
  };

  const emissionLevel = getEmissionLevel(averageCO2);

  return (
    <Card className="border-l-4 border-l-green-500">
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Leaf className="w-5 h-5 text-green-600" />
          Environmental Impact
        </CardTitle>
        <CardDescription>
          CO₂ emissions and environmental metrics based on energy consumption
        </CardDescription>
      </CardHeader>
      <CardContent>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          {/* Total CO2 Emissions */}
          <div className="p-4 bg-gradient-to-br from-green-50 to-green-100 dark:from-green-950 dark:to-green-900 rounded-lg">
            <div className="flex items-center gap-2 mb-2">
              <AlertTriangle className="w-4 h-4 text-green-600" />
              <span className="text-sm font-medium text-green-700 dark:text-green-300">Total CO₂</span>
            </div>
            <div className="text-2xl font-bold text-green-800 dark:text-green-200">
              {totalCO2.toFixed(1)}
            </div>
            <div className="text-sm text-green-600 dark:text-green-400">kg CO₂</div>
          </div>

          {/* Average CO2 per Hour */}
          <div className="p-4 bg-gradient-to-br from-blue-50 to-blue-100 dark:from-blue-950 dark:to-blue-900 rounded-lg">
            <div className="flex items-center gap-2 mb-2">
              <TrendingDown className="w-4 h-4 text-blue-600" />
              <span className="text-sm font-medium text-blue-700 dark:text-blue-300">Avg/Hour</span>
            </div>
            <div className="text-2xl font-bold text-blue-800 dark:text-blue-200">
              {averageCO2.toFixed(1)}
            </div>
            <div className="text-sm text-blue-600 dark:text-blue-400">kg CO₂/hr</div>
          </div>

          {/* Trees Equivalent */}
          <div className="p-4 bg-gradient-to-br from-emerald-50 to-emerald-100 dark:from-emerald-950 dark:to-emerald-900 rounded-lg">
            <div className="flex items-center gap-2 mb-2">
              <TreePine className="w-4 h-4 text-emerald-600" />
              <span className="text-sm font-medium text-emerald-700 dark:text-emerald-300">Trees Needed</span>
            </div>
            <div className="text-2xl font-bold text-emerald-800 dark:text-emerald-200">
              {treesEquivalent.toFixed(0)}
            </div>
            <div className="text-sm text-emerald-600 dark:text-emerald-400">trees/year</div>
          </div>

          {/* Emission Level */}
          <div className="p-4 bg-gradient-to-br from-gray-50 to-gray-100 dark:from-gray-950 dark:to-gray-900 rounded-lg">
            <div className="flex items-center gap-2 mb-2">
              <Leaf className="w-4 h-4 text-gray-600" />
              <span className="text-sm font-medium text-gray-700 dark:text-gray-300">Impact Level</span>
            </div>
            <div className="flex items-center gap-2">
              <Badge variant={emissionLevel.variant} className="text-lg px-3 py-1">
                {emissionLevel.level}
              </Badge>
            </div>
            <div className="text-sm text-gray-600 dark:text-gray-400 mt-1">
              {emissionLevel.level === "Low" ? "Excellent efficiency!" : 
               emissionLevel.level === "Moderate" ? "Room for improvement" : 
               "Consider energy optimization"}
            </div>
          </div>
        </div>

        {/* Environmental Insights */}
        <div className="mt-6 p-4 bg-accent/30 rounded-lg">
          <h4 className="font-medium mb-2 flex items-center gap-2">
            <Leaf className="w-4 h-4 text-green-600" />
            Environmental Insights
          </h4>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm">
            <div>
              <p className="text-muted-foreground">
                <span className="font-medium">Carbon Intensity:</span> {emissionFactor} kg CO₂ per kWh
              </p>
              <p className="text-muted-foreground">
                <span className="font-medium">Total Energy:</span> {totalKWH.toFixed(1)} kWh consumed
              </p>
            </div>
            <div>
              <p className="text-muted-foreground">
                <span className="font-medium">Reduction Potential:</span> Up to 20% with optimization
              </p>
              <p className="text-muted-foreground">
                <span className="font-medium">Target:</span> &lt;30 kg CO₂/hr for optimal efficiency
              </p>
            </div>
          </div>
        </div>
      </CardContent>
    </Card>
  );
}","codeFilePath":"/components/EnvironmentalImpact.tsx"}

{"code":"import { useState } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "./ui/card";
import { Button } from "./ui/button";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "./ui/table";
import { Badge } from "./ui/badge";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "./ui/dropdown-menu";
import { Download, FileText, FileSpreadsheet, Calendar, TrendingUp, Zap } from "lucide-react";

interface AnalyticsData {
  deviceId: string;
  timestamp: string;
  kvah: number;
  billing: number;
  kva: number;
  kw: number;
  kwh: number;
  pf: number;
  kvarh_lag: number;
  kvarh_lead: number;
  co2_emissions: number;
}

interface SummaryReportTableProps {
  data: AnalyticsData[];
  deviceName: string;
}

export function SummaryReportTable({ data, deviceName }: SummaryReportTableProps) {
  const [isExporting, setIsExporting] = useState(false);

  // Calculate summary metrics
  const calculateSummary = () => {
    const totalKWH = data.reduce((sum, item) => sum + item.kwh, 0);
    const averageKW = data.reduce((sum, item) => sum + item.kw, 0) / data.length;
    const maxKW = Math.max(...data.map(item => item.kw));
    const totalBilling = data.reduce((sum, item) => sum + item.billing, 0);
    const averagePF = data.reduce((sum, item) => sum + item.pf, 0) / data.length;
    const totalCO2 = data.reduce((sum, item) => sum + item.co2_emissions, 0);

    // Mock data for different time periods
    const todayKWH = totalKWH * 0.3; // 30% of total for "today"
    const yesterdayKWH = totalKWH * 0.25; // 25% for "yesterday"  
    const thisMonthKWH = totalKWH; // Full total for "this month"
    const lastReading = data[data.length - 1];

    return {
      todayKWH,
      yesterdayKWH,
      thisMonthKWH,
      lastReading,
      totalKWH,
      averageKW,
      maxKW,
      totalBilling,
      averagePF,
      totalCO2
    };
  };

  const summary = calculateSummary();

  const reportData = [
    {
      period: "Today",
      kwh: summary.todayKWH,
      billing: summary.todayKWH * 8.5,
      peakKW: summary.maxKW * 0.8,
      avgPF: summary.averagePF,
      co2: summary.todayKWH * 0.82,
      status: "Active",
      icon: Calendar
    },
    {
      period: "Yesterday", 
      kwh: summary.yesterdayKWH,
      billing: summary.yesterdayKWH * 8.5,
      peakKW: summary.maxKW * 0.75,
      avgPF: summary.averagePF * 0.95,
      co2: summary.yesterdayKWH * 0.82,
      status: "Completed",
      icon: TrendingUp
    },
    {
      period: "This Month",
      kwh: summary.thisMonthKWH,
      billing: summary.totalBilling,
      peakKW: summary.maxKW,
      avgPF: summary.averagePF,
      co2: summary.totalCO2,
      status: "In Progress",
      icon: Calendar
    },
    {
      period: "Last Reading",
      kwh: summary.lastReading.kwh,
      billing: summary.lastReading.billing,
      peakKW: summary.lastReading.kw,
      avgPF: summary.lastReading.pf,
      co2: summary.lastReading.co2_emissions,
      status: "Live",
      icon: Zap
    }
  ];

  const handleExport = async (format: 'excel' | 'pdf') => {
    setIsExporting(true);

    // Simulate export process
    await new Promise(resolve => setTimeout(resolve, 2000));

    // In a real application, you would generate and download the file here
    console.log(`Exporting ${format.toUpperCase()} report for ${deviceName}`);

    setIsExporting(false);
  };

  const getStatusVariant = (status: string) => {
    switch (status) {
      case "Active":
      case "Live":
        return "default";
      case "Completed":
        return "secondary";
      case "In Progress":
        return "outline";
      default:
        return "secondary";
    }
  };

  return (
    <Card>
      <CardHeader>
        <div className="flex items-center justify-between">
          <div>
            <CardTitle className="flex items-center gap-2">
              <FileText className="w-5 h-5 text-primary" />
              Summary Report
            </CardTitle>
            <CardDescription>
              Aggregated energy metrics for {deviceName}
            </CardDescription>
          </div>
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="outline" disabled={isExporting} className="gap-2">
                <Download className="w-4 h-4" />
                {isExporting ? "Exporting..." : "Download Report"}
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end">
              <DropdownMenuItem onClick={() => handleExport('excel')} className="gap-2">
                <FileSpreadsheet className="w-4 h-4" />
                Export as Excel
              </DropdownMenuItem>
              <DropdownMenuItem onClick={() => handleExport('pdf')} className="gap-2">
                <FileText className="w-4 h-4" />
                Export as PDF
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        </div>
      </CardHeader>
      <CardContent>
        <div className="rounded-lg border">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead className="w-[120px]">Period</TableHead>
                <TableHead>Energy (kWh)</TableHead>
                <TableHead>Billing (₹)</TableHead>
                <TableHead>Peak Demand (kW)</TableHead>
                <TableHead>Avg Power Factor</TableHead>
                <TableHead>CO₂ Emissions (kg)</TableHead>
                <TableHead>Status</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {reportData.map((row, index) => {
                const Icon = row.icon;
                return (
                  <TableRow key={index} className="hover:bg-muted/50">
                    <TableCell className="font-medium">
                      <div className="flex items-center gap-2">
                        <Icon className="w-4 h-4 text-muted-foreground" />
                        {row.period}
                      </div>
