{"code":"import { createContext, useContext, useState, ReactNode } from 'react';

interface User {
  id: string;
  name: string;
  email: string;
  role: string;
}

interface AuthContextType {
  user: User | null;
  login: (email: string, password: string) => Promise<boolean>;
  register: (name: string, email: string, password: string) => Promise<boolean>;
  logout: () => void;
  isLoading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const login = async (email: string, password: string): Promise<boolean> => {
    setIsLoading(true);

    // Simulate API call
    await new Promise(resolve => setTimeout(resolve, 1500));

    // Mock authentication - accept any email/password
    if (email && password) {
      const mockUser: User = {
        id: '1',
        name: 'Liam Gallagher',
        email: email,
        role: 'System Administrator'
      };
      setUser(mockUser);
      setIsLoading(false);
      return true;
    }

    setIsLoading(false);
    return false;
  };

  const register = async (name: string, email: string, password: string): Promise<boolean> => {
    setIsLoading(true);

    // Simulate API call
    await new Promise(resolve => setTimeout(resolve, 1500));

    // Mock registration - accept any valid data
    if (name && email && password) {
      const mockUser: User = {
        id: '1',
        name: name,
        email: email,
        role: 'System Administrator'
      };
      setUser(mockUser);
      setIsLoading(false);
      return true;
    }

    setIsLoading(false);
    return false;
  };

  const logout = () => {
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, login, register, logout, isLoading }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}","codeFilePath":"/components/AuthContext.tsx"}

{"code":"import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { Eye, EyeOff, Zap, Mail, Lock, User, Loader2, Sparkles, Shield } from 'lucide-react';
import { Button } from './ui/button';
import { Input } from './ui/input';
import { Label } from './ui/label';
import { Card, CardContent } from './ui/card';
import { useAuth } from './AuthContext';
import { ImageWithFallback } from './figma/ImageWithFallback';

export function Auth() {
  const [isLogin, setIsLogin] = useState(true);
  const [showPassword, setShowPassword] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: ''
  });
  const [errors, setErrors] = useState<string[]>([]);

  const { login, register, isLoading } = useAuth();

  // Floating particles animation data
  const particles = Array.from({ length: 20 }, (_, i) => ({
    id: i,
    x: Math.random() * 100,
    y: Math.random() * 100,
    delay: Math.random() * 5,
    duration: 10 + Math.random() * 10
  }));

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrors([]);

    const newErrors: string[] = [];

    if (!formData.email) newErrors.push('Email is required');
    if (!formData.password) newErrors.push('Password is required');
    if (!isLogin && !formData.name) newErrors.push('Name is required');

    if (newErrors.length > 0) {
      setErrors(newErrors);
      return;
    }

    try {
      let success = false;
      if (isLogin) {
        success = await login(formData.email, formData.password);
      } else {
        success = await register(formData.name, formData.email, formData.password);
      }

      if (!success) {
        setErrors(['Authentication failed. Please try again.']);
      }
    } catch (error) {
      setErrors(['An error occurred. Please try again.']);
    }
  };

  const toggleMode = () => {
    setIsLogin(!isLogin);
    setFormData({ name: '', email: '', password: '' });
    setErrors([]);
  };

  return (
    <div className="min-h-screen relative overflow-hidden">
      {/* Background Image with Overlay */}
      <div className="absolute inset-0">
        <ImageWithFallback
          src="https://images.unsplash.com/photo-1726795867801-63c0a37b80c6?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w3Nzg4Nzd8MHwxfHNlYXJjaHwxfHxlbmVyZ3klMjBzdXN0YWluYWJpbGl0eSUyMGdyZWVuJTIwdGVjaG5vbG9neSUyMG1vZGVybnxlbnwxfHx8fDE3NTU1MjA2NDh8MA&ixlib=rb-4.1.0&q=80&w=1080&utm_source=figma&utm_medium=referral"
          alt="Energy Technology Background"
          className="w-full h-full object-cover"
        />
        <div className="absolute inset-0 bg-gradient-to-br from-sidebar/40 via-sidebar/20 to-sidebar-accent/30" />
        <div className="absolute inset-0 bg-gradient-to-t from-sidebar/50 to-transparent" />
      </div>

      {/* Floating Particles */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        {particles.map((particle) => (
          <motion.div
            key={particle.id}
            className="absolute w-1 h-1 bg-sidebar-primary/30 rounded-full"
            style={{
              left: `${particle.x}%`,
              top: `${particle.y}%`,
            }}
            animate={{
              y: [0, -100, 0],
              opacity: [0, 1, 0],
              scale: [0, 1, 0],
            }}
            transition={{
              duration: particle.duration,
              delay: particle.delay,
              repeat: Infinity,
              ease: "easeInOut",
            }}
          />
        ))}
      </div>

      {/* Main Content */}
      <div className="relative z-10 min-h-screen flex items-center justify-center p-6">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          className="w-full max-w-md"
        >
          {/* Glass Card */}
          <Card className="backdrop-blur-xl bg-white/10 border border-white/20 shadow-2xl shadow-black/20 overflow-hidden">
            <CardContent className="p-0">
              {/* Header */}
              <div className="p-8 text-center border-b border-white/10">
                <motion.div
                  initial={{ scale: 0 }}
                  animate={{ scale: 1 }}
                  transition={{ delay: 0.2, type: "spring", stiffness: 200 }}
                  className="inline-flex items-center justify-center w-16 h-16 bg-sidebar-primary/20 backdrop-blur-sm rounded-full border border-sidebar-primary/30 mb-4"
                >
                  <Zap className="w-8 h-8 text-sidebar-primary" />
                </motion.div>

                <motion.h1 
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  transition={{ delay: 0.3 }}
                  className="text-2xl font-bold text-white mb-2"
                >
                  EMS Portal
                </motion.h1>

                <motion.p 
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  transition={{ delay: 0.4 }}
                  className="text-white/70"
                >
                  Energy Management System
                </motion.p>
              </div>

              {/* Form */}
              <div className="p-8">
                <AnimatePresence mode="wait">
                  <motion.div
                    key={isLogin ? 'login' : 'register'}
                    initial={{ opacity: 0, x: isLogin ? -20 : 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: isLogin ? 20 : -20 }}
                    transition={{ duration: 0.3 }}
                  >
                    <div className="flex items-center justify-center mb-6">
                      <div className="flex bg-white/10 backdrop-blur-sm rounded-full p-1 border border-white/20">
                        <Button
                          type="button"
                          variant={isLogin ? "default" : "ghost"}
                          size="sm"
                          onClick={() => setIsLogin(true)}
                          className={`rounded-full px-6 transition-all duration-300 ${
                            isLogin 
                              ? 'bg-sidebar-primary text-sidebar-primary-foreground shadow-lg' 
                              : 'text-white/70 hover:text-white hover:bg-white/10'
                          }`}
                        >
                          <Shield className="w-4 h-4 mr-2" />
                          Login
                        </Button>
                        <Button
                          type="button"
                          variant={!isLogin ? "default" : "ghost"}
                          size="sm"
                          onClick={() => setIsLogin(false)}
                          className={`rounded-full px-6 transition-all duration-300 ${
                            !isLogin 
                              ? 'bg-sidebar-primary text-sidebar-primary-foreground shadow-lg' 
                              : 'text-white/70 hover:text-white hover:bg-white/10'
                          }`}
                        >
                          <Sparkles className="w-4 h-4 mr-2" />
                          Register
                        </Button>
                      </div>
                    </div>

                    <form onSubmit={handleSubmit} className="space-y-6">
